class Persona:
    def __init__(self, nombre, edad):
        self.nombre = nombre
        self.edad = edad

    def saludar(self):
        return f"Hola, soy {self.nombre}"

persona = Persona("Carlos", 25)
print(persona.saludar())

class SerVivo:
    def __init__(self, nombre):
        self.nombre = nombre

class Humano(SerVivo):
    def hablar(self):
        return "Hola!"

humano = Humano("Carlos")
print(humano.hablar())
